package pe.edu.utp.tmo.service.impl;
import java.time.*; import java.util.*; import java.util.stream.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import pe.edu.utp.tmo.dao.*; import pe.edu.utp.tmo.dto.response.*; import pe.edu.utp.tmo.exception.AccesoNoAutorizadoException; import pe.edu.utp.tmo.model.entity.*; import pe.edu.utp.tmo.model.enums.*; import pe.edu.utp.tmo.service.DashboardService; import pe.edu.utp.tmo.util.SlaEvaluator;
@Service public class DashboardServiceImpl implements DashboardService{ private final UsuarioDAO usuarios; private final CasoDAO casos; private final RegistroTMODAO registros; private final CatalogCacheService cache; private final SlaEvaluator sla; public DashboardServiceImpl(UsuarioDAO usuarios,CasoDAO casos,RegistroTMODAO registros,CatalogCacheService cache,SlaEvaluator sla){this.usuarios=usuarios;this.casos=casos;this.registros=registros;this.cache=cache;this.sla=sla;} @Transactional(readOnly=true) public DashboardResponse resumen(String correo,LocalDateTime inicio,LocalDateTime fin){Usuario u=usuarios.buscarPorCorreo(correo).orElseThrow(()->new AccesoNoAutorizadoException("Usuario no autorizado.")); if(u.getRol()==RolUsuario.ANALISTA) throw new AccesoNoAutorizadoException("Dashboard restringido."); List<Caso> cs=casos.listarPorPeriodo(inicio,fin).stream().filter(c->u.getRol()!=RolUsuario.SUPERVISOR || c.getAnalista().getArea().equalsIgnoreCase(u.getArea())).toList(); Set<Long> ids=cs.stream().map(Caso::getId).collect(Collectors.toSet()); List<RegistroTMO> rs=registros.listarPorPeriodo(inicio,fin).stream().filter(r->ids.contains(r.getCaso().getId())).toList(); long alertas=rs.stream().filter(r->sla.excede(r.getTmoSegundos(),cache.sla(r.getCaso().getTipoCaso()).orElse(null))).count(); Map<String,List<RegistroTMO>> m=rs.stream().collect(Collectors.groupingBy(r->r.getCaso().getTipoCaso().name())); List<KpiPorTipoResponse> k=m.entrySet().stream().map(e->new KpiPorTipoResponse(e.getKey(),e.getValue().size(),e.getValue().stream().mapToLong(RegistroTMO::getTmoSegundos).average().orElse(0))).toList(); return new DashboardResponse(cs.stream().filter(c->c.getEstado()==EstadoCaso.ABIERTO).count(),cs.stream().filter(c->c.getEstado()==EstadoCaso.CERRADO).count(),rs.stream().mapToLong(RegistroTMO::getTmoSegundos).average().orElse(0),alertas,k);} }
